// ═══════════════════════════════════════════════════════════════════
// 🚫 FILTRO DE STATUS UPDATES - ANTI-LOOP (UROBOT V2)
// ═══════════════════════════════════════════════════════════════════

const data = $input.first()?.json || {};

// Chat Trigger support
if (data.chatInput && !data.messages) {
  const mockPhone = '526674492872';
  return [{
    json: {
      messages: [{
        from: mockPhone,
        id: 'chat-trigger-' + Date.now(),
        timestamp: Math.floor(Date.now() / 1000).toString(),
        type: 'text',
        text: { body: data.chatInput }
      }],
      metadata: { phone_number_id: 'test-phone-id' },
      _fromChatTrigger: true,
      _sessionId: data.sessionId
    }
  }];
}

if (data.statuses && data.statuses.length > 0) return [];
if (!data.messages || data.messages.length === 0) return [];
const msg = data.messages[0];
if (!msg.from) return [];

const referral = msg.referral || {};
const esMetaAds = !!(referral.source_url || referral.headline || referral.body || referral.ctwa_clid);

return [{
  json: {
    ...data,
    es_meta_ads: esMetaAds,
    meta_source_url: referral.source_url || null,
    meta_headline: referral.headline || null,
    meta_body: referral.body || null,
    meta_ctwa_clid: referral.ctwa_clid || null,
    meta_source_id: referral.source_id || null
  }
}];

// ═══════════════════════════════════════════════════════════════════
// ⚡ RATE LIMIT CHECK (mensaje antiguo > 5 min)
// ═══════════════════════════════════════════════════════════════════

const triggerData = $input.first()?.json || {};
const messages = triggerData.messages || [];
const message = messages[0] || {};

if (!messages.length || !message.from) {
  return [{ json: { ...triggerData, _rate_limit_ok: false, _reason: 'no_message' } }];
}

const timestamp = parseInt(message.timestamp || '0');
const now = Math.floor(Date.now() / 1000);
const messageAge = now - timestamp;

if (messageAge > 300) {
  return [{ json: { ...triggerData, _rate_limit_ok: false, _reason: 'mensaje_antiguo' } }];
}

return [{
  json: {
    ...triggerData,
    _rate_limit_ok: true,
    _telefono: message.from,
    _mensaje_id: message.id
  }
}];

// ═══════════════════════════════════════════════════════════════════
// 1️⃣ VALIDAR Y NORMALIZAR (UROBOT V2)
// ═══════════════════════════════════════════════════════════════════

const setTexto = $input.first()?.json || {};
const filterData = $('🚫 Filtrar Status').first()?.json || {};
const rateData = $('⚡ Rate Limit Check').first()?.json || {};

const messages = filterData.messages || [];
const message = messages[0] || {};
const metadata = filterData.metadata || {};

const telefono = message.from || rateData._telefono || '';
const mensajeId = message.id || rateData._mensaje_id || 'msg-' + Date.now();
const msgType = message.type || 'text';
const fromChatTrigger = filterData._fromChatTrigger === true;
const sessionId = filterData._sessionId || mensajeId;

let mensajeUsuario = setTexto.mensajeUsuario || '';
if (!mensajeUsuario && msgType === 'text') {
  mensajeUsuario = message.text?.body || '';
}

const contacts = filterData.contacts || [];
let nombreUsuario = contacts[0]?.profile?.name || 'Usuario';

const esMetaAds = filterData.es_meta_ads === true;
const metaCtwaClid = filterData.meta_ctwa_clid || null;
const metaHeadline = filterData.meta_headline || null;
const metaSourceUrl = filterData.meta_source_url || null;

let fuente = 'organico';
if (esMetaAds) fuente = 'meta_ads';

let tipoMedia = 'texto';
switch (msgType) {
  case 'image': tipoMedia = 'imagen'; break;
  case 'audio': tipoMedia = 'audio'; break;
  case 'document': tipoMedia = 'documento'; break;
  default: tipoMedia = 'texto';
}

return [{
  json: {
    telefono,
    nombreUsuario,
    mensajeUsuario: mensajeUsuario.trim(),
    mensaje_id_externo: mensajeId,
    external_chat_id: telefono,
    tipoMedia,
    fuente,
    es_meta_ads: esMetaAds,
    meta_ctwa_clid: metaCtwaClid,
    meta_headline: metaHeadline,
    meta_source_url: metaSourceUrl,
    phone_number_id: metadata.phone_number_id || '',
    _fromChatTrigger: fromChatTrigger,
    _sessionId: sessionId,
    timestamp: message.timestamp || Math.floor(Date.now() / 1000).toString()
  }
}];

// ═══════════════════════════════════════════════════════════════════
// 5️⃣ PROCESAR CONTEXTO (UROBOT V2)
// ═══════════════════════════════════════════════════════════════════

const normalizado = $('1️⃣ Validar y Normalizar').first()?.json || {};
const convResult = $('2️⃣ Upsert Conversación').first()?.json || {};
const ctxRawInput = $input.first()?.json?.contexto;

let ctx = {};
try {
  ctx = typeof ctxRawInput === 'string' ? JSON.parse(ctxRawInput) : (ctxRawInput || {});
} catch (e) {
  ctx = {};
}

const {
  historial_mensajes: historial = '',
  ultimo_mensaje_bot: ultimoBot = '',
  sintomas_acumulados: sintomasRaw = [],
  banderas_rojas: banderasPrev = [],
  lead_id: leadId = null,
  es_paciente: esPaciente = false,
  pregunto_precio: preguntoPrecio = false,
  funnel_stage: funnelPrevio = '01_contactado',
  total_mensajes: totalMensajes = 0,
  nombre: nombreContexto,
  temperatura = 'frio',
  score_total: scoreTotal = 0,
  es_urgencia: esUrgencia = false,
  tiene_cita_pendiente: tieneCita = false,
  cita_pendiente: citaPendiente = null,
  accion_recomendada: accionRecomendada = null,
  es_primera_interaccion: esPrimera = true
} = ctx;

const sintomasArray = Array.isArray(sintomasRaw) ? sintomasRaw : [];
const sintomasTexto = sintomasArray.join(', ');

const nombreFinal = nombreContexto && nombreContexto !== 'Usuario'
  ? nombreContexto
  : (normalizado.nombreUsuario || 'Usuario');

return [{
  json: {
    ...ctx,
    lead_id: leadId,
    telefono: normalizado.telefono,
    nombreUsuario: nombreFinal,
    nombre_confirmado: ctx.nombre_confirmado ? nombreContexto : null,
    mensajeUsuario: normalizado.mensajeUsuario,
    tipoMedia: normalizado.tipoMedia,
    phone_number_id: normalizado.phone_number_id,
    conversacion_id: convResult.conversacion_id,
    historial_mensajes: historial,
    ultimo_mensaje_bot: ultimoBot,
    sintomas_texto: sintomasTexto,
    sintomas_acumulados: sintomasArray,
    banderas_rojas: banderasPrev,
    es_paciente: esPaciente,
    pregunto_precio: preguntoPrecio,
    funnel_stage: funnelPrevio,
    total_mensajes: totalMensajes,
    temperatura,
    score_total: scoreTotal,
    es_urgencia: esUrgencia,
    tiene_cita_pendiente: tieneCita,
    cita_pendiente: citaPendiente,
    accion_recomendada: accionRecomendada,
    es_primera_interaccion: esPrimera,
    es_meta_ads: normalizado.es_meta_ads,
    meta_ctwa_clid: normalizado.meta_ctwa_clid,
    meta_headline: normalizado.meta_headline,
    fuente: normalizado.fuente,
    _fromChatTrigger: normalizado._fromChatTrigger
  }
}];

// ═══════════════════════════════════════════════════════════════════
// 9️⃣ FORMATEAR CONTEXTO PARA AGENTE (UROBOT V2.1)
// ═══════════════════════════════════════════════════════════════════
// Merge 3 sources:
//   - Node 5: telefono, mensajeUsuario, historial BD, cita pendiente
//   - Node 7: análisis Gemini (intención, perfil, síntomas, barreras)
//   - $input: scoring from Node 8 via Anti-Baneo chain

const node5 = $('5️⃣ Procesar Contexto').first()?.json || {};

// ⚡ FIX: Read rich analysis from Node 7 (was being lost after Postgres call)
let node7 = {};
try {
  node7 = $('7️⃣ Procesar Análisis').first()?.json || {};
} catch (e) {
  node7 = {};
}

const node8 = $input.first()?.json || {};

// Merge: node5 (base) → node7 (analysis) → node8 (scoring overrides)
const ctx = { ...node5, ...node7, ...node8 };

const historialBD = ctx.historial_mensajes || '';
const ultimoBot = ctx.ultimo_mensaje_bot || '';
const totalMensajes = ctx.total_mensajes || 0;
const esPrimera = ctx.es_primera_interaccion ?? (totalMensajes <= 1);

const nombreFinal = ctx.nombre_detectado || ctx.nombreUsuario || 'Usuario';
const tenemosNombre = nombreFinal !== 'Usuario';

let contextoContacto = '';

// ═══ PACIENTE ═══
contextoContacto += `PACIENTE: ${nombreFinal}`;
if (!tenemosNombre) contextoContacto += ' (nombre desconocido — pregúntalo de forma natural)';
contextoContacto += '\n';

if (esPrimera) {
  contextoContacto += '⚡ PRIMERA INTERACCIÓN — Sé especialmente cálido y profesional\n';
}

// ═══ SCORING ═══
contextoContacto += `📊 Temp: ${ctx.temperatura || 'frio'} | Score: ${ctx.score_total || 0}/100 | Funnel: ${ctx.funnel_stage || ctx.etapa_funnel || '01_contactado'} | Msgs: ${totalMensajes}\n`;

// ═══ ANÁLISIS DEL MENSAJE ACTUAL (from Gemini via Node 7) ═══
const intencion = ctx.intencion_principal || ctx.intencion || '';
const perfil = ctx.perfil_paciente || '';
const emociones = Array.isArray(ctx.emociones_detectadas) ? ctx.emociones_detectadas : [];
const nivelCompromiso = ctx.nivel_compromiso || 0;
const prediccion = ctx.prediccion_conversion || '';
const barrera = ctx.barrera_principal || 'ninguna';
const detalleBarrera = ctx.detalle_barrera || '';
const incentivo = ctx.incentivo_sugerido || '';
const siguientePaso = ctx.siguiente_paso_ideal || '';

if (intencion) {
  contextoContacto += `\n🎯 INTENCIÓN ACTUAL: ${intencion.replace(/_/g, ' ')}`;
  if (perfil) contextoContacto += ` | Perfil: ${perfil.replace(/_/g, ' ')}`;
  if (nivelCompromiso) contextoContacto += ` | Compromiso: ${nivelCompromiso}/10`;
  contextoContacto += '\n';
}

if (prediccion && prediccion !== 'media') {
  contextoContacto += `📈 Predicción conversión: ${prediccion}`;
  if (incentivo && incentivo !== 'ninguno') contextoContacto += ` → Estrategia: ${incentivo.replace(/_/g, ' ')}`;
  contextoContacto += '\n';
}

if (emociones.length > 0) {
  contextoContacto += `💭 Emociones detectadas: ${emociones.join(', ')}\n`;
}

if (barrera !== 'ninguna' && barrera) {
  contextoContacto += `⚠️ BARRERA: ${barrera.replace(/_/g, ' ')}`;
  if (detalleBarrera) contextoContacto += ` — ${detalleBarrera}`;
  contextoContacto += '\n';
}

if (siguientePaso) {
  contextoContacto += `➡️ SIGUIENTE PASO IDEAL: ${siguientePaso}\n`;
}

// ═══ SÍNTOMAS ESTRUCTURADOS (from Gemini analysis) ═══
const sintomasEstructurados = Array.isArray(ctx.sintomas_estructurados) ? ctx.sintomas_estructurados.filter(s => s && s.nombre) : [];
const sintomasPrevios = Array.isArray(ctx.sintomas_acumulados) ? ctx.sintomas_acumulados : [];

if (sintomasEstructurados.length > 0) {
  contextoContacto += '\n🩺 SÍNTOMAS DETECTADOS:\n';
  for (const s of sintomasEstructurados) {
    const sev = s.severidad ? ` [${s.severidad}]` : '';
    const tiempo = s.tiempo_evolucion ? ` — ${s.tiempo_evolucion}` : '';
    const desc = s.descripcion_original && s.descripcion_original !== s.nombre ? ` (paciente dijo: "${s.descripcion_original}")` : '';
    contextoContacto += `  • ${(s.nombre || '').replace(/_/g, ' ')}${sev}${tiempo}${desc}\n`;
  }
} else if (sintomasPrevios.length > 0) {
  const nombres = sintomasPrevios.map(s => typeof s === 'string' ? s : s.nombre).filter(Boolean);
  if (nombres.length > 0) {
    contextoContacto += `\n🩺 SÍNTOMAS PREVIOS: ${nombres.join(', ')}\n`;
  }
}

// ═══ BANDERAS ROJAS ═══
const banderas = Array.isArray(ctx.banderas_rojas) ? ctx.banderas_rojas : [];
if (banderas.length > 0) {
  contextoContacto += `\n🚨 BANDERAS ROJAS: ${banderas.map(b => b.replace(/_/g, ' ')).join(', ')}\n`;
}

if (ctx.es_urgencia || ctx.es_urgencia_medica) {
  contextoContacto += '⚠️ URGENCIA MÉDICA — Priorizar atención inmediata\n';
}

// ═══ DATOS CLÍNICOS EXTRA ═══
const antecedentes = Array.isArray(ctx.antecedentes_mencionados) ? ctx.antecedentes_mencionados.filter(Boolean) : [];
const medicamentos = Array.isArray(ctx.medicamentos_mencionados) ? ctx.medicamentos_mencionados.filter(Boolean) : [];
const edad = ctx.edad_detectada || null;

if (antecedentes.length > 0 || medicamentos.length > 0 || edad) {
  contextoContacto += '\n📋 DATOS CLÍNICOS:\n';
  if (edad) contextoContacto += `  • Edad: ${edad}\n`;
  if (antecedentes.length > 0) contextoContacto += `  • Antecedentes: ${antecedentes.join(', ')}\n`;
  if (medicamentos.length > 0) contextoContacto += `  • Medicamentos: ${medicamentos.join(', ')}\n`;
}

// ═══ PRECIO ═══
if (ctx.pregunto_precio) {
  contextoContacto += '\n💰 Ha preguntado por precios';
  const sensibilidad = ctx.nivel_sensibilidad_precio || (ctx.senales_precio?.nivel_sensibilidad) || '';
  if (sensibilidad && sensibilidad !== 'ninguna') {
    contextoContacto += ` (sensibilidad: ${sensibilidad})`;
  }
  contextoContacto += '\n';
}

// ═══ CITA PENDIENTE ═══
if (ctx.tiene_cita_pendiente && ctx.cita_pendiente) {
  const c = ctx.cita_pendiente;
  contextoContacto += `\n📅 CITA PENDIENTE:\n- Fecha: ${c.fecha_hora}\n- Sede: ${c.sede || 'Por definir'}\n- Estado: ${c.estado} / ${c.confirmacion || 'sin confirmar'}\n- Tipo: ${c.tipo || 'consulta'}\n`;
}

// ═══ ACCIÓN RECOMENDADA ═══
if (ctx.accion_recomendada) {
  contextoContacto += `\n🎯 Acción sistema: ${ctx.accion_recomendada.replace(/_/g, ' ')}\n`;
}

// ═══ META ADS ═══
if (ctx.es_meta_ads) {
  contextoContacto += '\n📱 Llegó por anuncio de Facebook/Instagram';
  if (ctx.meta_headline) contextoContacto += ` — "${ctx.meta_headline}"`;
  contextoContacto += '\n';
}

// ═══ HISTORIAL ═══
if (historialBD) {
  contextoContacto += `\n═══ HISTORIAL RECIENTE ═══\n${historialBD}\n═════════════════════════════\n`;
}

return [{
  json: {
    ...ctx,
    contextoContacto,
    origen: 'urobot'
  }
}];

