// ═══════════════════════════════════════════════════════════════
// 🧹 LIMPIAR RESPUESTA + FALLBACK ante falla del AI Agent
// ═══════════════════════════════════════════════════════════════

// Detectar si el AI Agent falló (continueOnFail propagates error)
const aiOutput = $input.first();
const hasError = aiOutput?.json?.error || !aiOutput?.json?.output;

if (hasError) {
  const errorMsg = aiOutput?.json?.error?.message || aiOutput?.json?.errorMessage || 'AI Agent failed';
  console.log(`🚨 AI Agent ERROR: ${errorMsg}`);

  // Fallback: send a safe generic message
  const ctx = $('9️⃣ Formatear Contexto').first()?.json || {};
  const nombre = (ctx.nombreUsuario || '').split(' ')[0];
  const saludo = nombre ? `${nombre}, gracias` : 'Gracias';

  return [{
    json: {
      text: `${saludo} por escribirnos. En este momento estoy teniendo dificultades técnicas. Un momento por favor, le atenderé en breve.`,
      is_fallback: true,
      ai_error: errorMsg
    }
  }];
}

// ── Normal flow: clean the AI response ──
const raw = (aiOutput.json.output || aiOutput.json.text || aiOutput.json.response || '').trim();

if (!raw) {
  console.log('🚨 AI Agent returned empty response');
  return [{
    json: {
      text: 'Gracias por escribirnos. Un momento por favor, le atenderé en breve.',
      is_fallback: true,
      ai_error: 'empty_response'
    }
  }];
}

// Clean WhatsApp formatting artifacts
let cleaned = raw
  .replace(/\*\*([^*]+)\*\*/g, '*$1*')  // **bold** → *bold*
  .replace(/^#+\s*/gm, '')                 // Remove markdown headers
  .replace(/```[\s\S]*?```/g, '')          // Remove code blocks
  .replace(/\[([^\]]+)\]\([^)]+\)/g, '$1') // [text](url) → text
  .replace(/\n{3,}/g, '\n\n')              // Max 2 newlines
  .trim();

// Truncate if too long for WhatsApp
if (cleaned.length > 4000) {
  cleaned = cleaned.substring(0, 3900) + '\n\n_Le envío el resto en un momento..._';
}

return [{ json: { text: cleaned, is_fallback: false } }];

// ═══════════════════════════════════════════════════════════════════
// 7️⃣ PROCESAR ANÁLISIS (UROBOT V2 - Behavioral Intelligence + Clinical)
// ═══════════════════════════════════════════════════════════════════

const ctx = $('5️⃣ Procesar Contexto').first()?.json || {};
const analysisRaw = $input.first()?.json?.text || '{}';

// === PARSE DEL JSON DE LA IA ===
let analisis = {};
try {
  let cleaned = analysisRaw.replace(/```json|```/gi, '').trim();
  const match = cleaned.match(/\{[\s\S]*\}/);
  if (match) cleaned = match[0];
  analisis = JSON.parse(cleaned);
} catch (e) {
  analisis = { 
    intencion_principal: 'otro', 
    perfil_paciente: 'solo_curiosidad',
    emociones_detectadas: [],
    sintomas_estructurados: [], 
    banderas_rojas: [],
    urgencia_percibida: 'normal',
    nivel_compromiso: 5,
    prediccion_conversion: 'media',
    incentivo_sugerido: 'ninguno',
    barrera_principal: 'ninguna',
    senales_precio: { pregunto_precio: false, nivel_sensibilidad: 'ninguna' }
  };
}

// === INTENCIÓN ===
const intencionPrincipal = analisis.intencion_principal || analisis.intencion || 'otro';

// === PERFIL Y COMPORTAMIENTO ===
const perfilPaciente = analisis.perfil_paciente || 'solo_curiosidad';
const emocionesDetectadas = Array.isArray(analisis.emociones_detectadas) ? analisis.emociones_detectadas : [];
const nivelCompromiso = analisis.nivel_compromiso || 5;
const prediccionConversion = analisis.prediccion_conversion || 'media';
const incentivoSugerido = analisis.incentivo_sugerido || 'ninguno';
const barrieraPrincipal = analisis.barrera_principal || 'ninguna';
const detalleBarrera = analisis.detalle_barrera || '';

// === SEÑALES DE PRECIO ===
const senalesPrecio = analisis.senales_precio || {};
const preguntoPrecioNuevo = senalesPrecio.pregunto_precio || analisis.pregunto_precio || false;
const mencionoPresupuesto = senalesPrecio.menciono_presupuesto || false;
const indicadoresPrecio = Array.isArray(senalesPrecio.indicadores) ? senalesPrecio.indicadores : [];
const nivelSensibilidadPrecio = senalesPrecio.nivel_sensibilidad || 'ninguna';

// === DATOS RELEVANTES ===
const datosRelevantes = analisis.datos_relevantes || {};
const ocupacion = datosRelevantes.ocupacion || null;
const antecedentesMencionados = Array.isArray(datosRelevantes.antecedentes_mencionados) ? datosRelevantes.antecedentes_mencionados : [];
const medicamentosMencionados = Array.isArray(datosRelevantes.medicamentos_mencionados) ? datosRelevantes.medicamentos_mencionados : [];
const paraQuien = datosRelevantes.para_quien || 'para_si_mismo';

// === OTROS CAMPOS ===
const sentimiento = analisis.sentimiento || 'neutro';
const tonoEmocional = analisis.tono_emocional || emocionesDetectadas.join(', ');
const fechaMencionada = analisis.fecha_mencionada || null;
const horaMencionada = analisis.hora_mencionada || null;
const edadDetectada = analisis.edad_detectada || null;
const siguientePaso = analisis.siguiente_paso_ideal || '';

// === VALIDACIÓN DE NOMBRE (anti-síntoma) ===
const terminosMedicos = new Set([
  'disuria', 'hematuria', 'polaquiuria', 'nicturia', 'incontinencia',
  'litiasis', 'varicocele', 'hidrocele', 'fimosis', 'prostatitis',
  'cistitis', 'pielonefritis', 'ureteritis', 'uretritis',
  'disfuncion', 'erectil', 'impotencia', 'infertilidad',
  'dolor', 'ardor', 'sangre', 'piedra', 'calculo', 'riñon',
  'hola', 'buenos', 'dias', 'días', 'buenas', 'tardes', 'noches',
  'gracias', 'ok', 'si', 'sí', 'no', 'claro', 'dale', 'va',
  'perfecto', 'bien', 'orina', 'orinar', 'prostata', 'próstata',
  'testiculo', 'testículo', 'pene', 'vejiga', 'retencion'
]);
const rawNombre = analisis.nombre_detectado || null;
const nombreDetectado = (rawNombre && !terminosMedicos.has(rawNombre.toLowerCase().trim()) && rawNombre.length > 1 && rawNombre.length < 60) ? rawNombre : null;

// === PROCESAMIENTO DE URGENCIA (NUNCA BAJAR) ===
const urgenciaNueva = analisis.urgencia_percibida || 'normal';
const urgenciaPrevia = ctx.urgencia_percibida || 'normal';
const ordenUrgencia = { 'normal': 1, 'alta': 2, 'emergencia': 3 };
const urgenciaFinal = (ordenUrgencia[urgenciaNueva] || 1) >= (ordenUrgencia[urgenciaPrevia] || 1)
  ? urgenciaNueva 
  : urgenciaPrevia;
const esUrgenciaMedica = urgenciaFinal === 'emergencia' || urgenciaFinal === 'alta';

// === SÍNTOMAS ESTRUCTURADOS ===
const sintomasNuevos = Array.isArray(analisis.sintomas_estructurados)
  ? analisis.sintomas_estructurados.filter(s => s && s.nombre)
  : [];

let sintomasPrevios = [];
if (Array.isArray(ctx.sintomas_acumulados)) {
  sintomasPrevios = ctx.sintomas_acumulados.map(s => {
    if (typeof s === 'string') {
      return { nombre: s, descripcion_original: s, severidad: 'moderada', tiempo_evolucion: null };
    }
    return s;
  });
}

// Merge inteligente: no duplicar por nombre, actualizar severidad si es mayor
const ordenSeveridad = { 'leve': 1, 'moderada': 2, 'severa': 3 };
const sintomasMerged = [...sintomasPrevios];
for (const sintomaNew of sintomasNuevos) {
  const nombreLower = (sintomaNew.nombre || '').toLowerCase();
  const existente = sintomasMerged.find(s => (s.nombre || '').toLowerCase() === nombreLower);
  if (!existente) {
    sintomasMerged.push(sintomaNew);
  } else {
    const sevExistente = ordenSeveridad[existente.severidad] || 2;
    const sevNueva = ordenSeveridad[sintomaNew.severidad] || 2;
    if (sevNueva > sevExistente) existente.severidad = sintomaNew.severidad;
    if (!existente.tiempo_evolucion && sintomaNew.tiempo_evolucion) {
      existente.tiempo_evolucion = sintomaNew.tiempo_evolucion;
    }
    if (sintomaNew.descripcion_original && sintomaNew.descripcion_original !== sintomaNew.nombre) {
      existente.descripcion_original = sintomaNew.descripcion_original;
    }
  }
}
const sintomasNombres = sintomasMerged.map(s => s.nombre).filter(Boolean);

// === BANDERAS ROJAS (ACUMULATIVAS) ===
const banderasNuevas = Array.isArray(analisis.banderas_rojas) ? analisis.banderas_rojas : [];
const banderasPrevias = Array.isArray(ctx.banderas_rojas_previas) ? ctx.banderas_rojas_previas : [];
const banderasMerged = [...new Set([...banderasPrevias, ...banderasNuevas])];

// === TIEMPO DE EVOLUCIÓN ===
const tiempoEvolucion = analisis.tiempo_evolucion_general ||
  sintomasNuevos.find(s => s.tiempo_evolucion)?.tiempo_evolucion ||
  ctx.tiempo_evolucion || null;

// === PREGUNTÓ PRECIO (ACUMULATIVO) ===
const preguntoPrecio = preguntoPrecioNuevo || ctx.pregunto_precio || false;

// === RETORNAR DATOS COMPLETOS ===
return [{
  json: {
    ...ctx,
    intencion_principal: intencionPrincipal,
    intencion: intencionPrincipal,
    perfil_paciente: perfilPaciente,
    emociones_detectadas: emocionesDetectadas,
    nivel_compromiso: nivelCompromiso,
    prediccion_conversion: prediccionConversion,
    incentivo_sugerido: incentivoSugerido,
    barrera_principal: barrieraPrincipal,
    detalle_barrera: detalleBarrera,
    senales_precio: senalesPrecio,
    nivel_sensibilidad_precio: nivelSensibilidadPrecio,
    indicadores_precio: indicadoresPrecio,
    menciono_presupuesto: mencionoPresupuesto,
    ocupacion,
    antecedentes_mencionados: antecedentesMencionados,
    medicamentos_mencionados: medicamentosMencionados,
    para_quien: paraQuien,
    edad_detectada: edadDetectada,
    sentimiento,
    tono_emocional: tonoEmocional,
    nombre_detectado: nombreDetectado,
    siguiente_paso_ideal: siguientePaso,
    fecha_mencionada: fechaMencionada,
    hora_mencionada: horaMencionada,
    urgencia_percibida: urgenciaFinal,
    es_urgencia_medica: esUrgenciaMedica,
    sintomas_estructurados: sintomasMerged,
    sintomas_merged: sintomasNombres,
    banderas_rojas: banderasMerged,
    tiempo_evolucion: tiempoEvolucion,
    pregunto_precio: preguntoPrecio,
    tiene_historial_real: (ctx.historial_mensajes || '').length > 50,
    es_primera_interaccion: !((ctx.historial_mensajes || '').length > 50) && (ctx.total_mensajes || 0) <= 1
  }
}];

// ═══════════════════════════════════════════════════════════════════
// 🏷️ CLASIFICADOR HÍBRIDO UROBOT v2 - Corregido usted/tú + newlines
// ═══════════════════════════════════════════════════════════════════

const ctx = $('9️⃣ Formatear Contexto').first()?.json || {};
const limpioData = $('🧹 Limpiar Respuesta').first()?.json || {};
const texto = limpioData.text || '';
const t = texto.toLowerCase();
// Flatten newlines for cross-paragraph matching
const tf = t.replace(/\n+/g, ' ');
const parrafos = texto.split(/\n\n+/).filter(p => p.trim());
const ultimoParrafo = (parrafos[parrafos.length - 1] || texto).toLowerCase();

function clasificarHibrido() {
  // PASO 1: CITA CONFIRMADA (alta prioridad) — only hard confirmations
  if (/qued(ó|a)? (agendad|reservad|formalmente)|ya qued(ó|a)|[ts]u cita.*confirm|listo.*reserv|queda reservad/i.test(tf)) return 'confirmacion';

  // PASO 2: HORARIOS OFRECIDOS — bot muestra disponibilidad concreta (before nombre check!)
  // Direct keywords (most reliable)
  if (/tengo (espacio|disponibilidad|lugar)|hay (espacio|disponibilidad|lugar)/i.test(tf)) return 'horarios_dados';
  if (/qué horario [lts]e (acomoda|conviene|funciona|queda)/i.test(tf)) return 'horarios_dados';
  if (/alguna de estas opciones/i.test(tf)) return 'horarios_dados';
  // Time patterns: days + times in same message
  if (/(lunes|martes|mi[eé]rcoles|jueves|viernes|s[aá]bado)/.test(tf) && /\d{1,2}:\d{2}\s*(pm|am)/i.test(tf)) return 'horarios_dados';
  // Ultimo parrafo patterns (usted-compatible)
  if (/[lts]e (queda|funciona|parece|acomoda|conviene).*horario/i.test(ultimoParrafo)) return 'horarios_dados';
  if (/\d{1,2}:\d{2}\s*(pm|am)/i.test(ultimoParrafo) && /\?/.test(ultimoParrafo)) return 'horarios_dados';
  if (/apartarlo|reserv[ae]r[ls]e|apart[ae]r[ls]e/i.test(ultimoParrafo)) return 'horarios_dados';

  // PASO 2b: CONFIRMACION by name request (only if no times were offered)
  if (/confirm[ae]me [ts]u nombre|[ts]u nombre completo|para (generar|abrir).*expediente/i.test(ultimoParrafo)) return 'confirmacion';

  // PASO 3: OFERTA DE CITA — bot ofrece buscar horario
  if (/[lts]e (gustaría|interesa|parece).*agendar|[lts]e ofrezca.*espacio|quiere[ns]?.*cita/i.test(ultimoParrafo)) return 'oferta_cita';
  if (/[lts]e busco un (horario|espacio)|buscar[lts]e.*(horario|espacio|cita)/i.test(tf)) return 'oferta_cita';
  if (/gustaría que.*busque.*(espacio|horario|cita)/i.test(tf)) return 'oferta_cita';
  if (/quiere que.*(agend|reserv|apart)/i.test(tf)) return 'oferta_cita';

  // PASO 4: DESCUBRIMIENTO — bot pregunta sobre síntomas
  if (/\?/.test(ultimoParrafo) && /s[ií]ntoma|siente|cu[aá]ndo|molest|orin|dolor|ard|sangr|pr[oó]stat|malestar|preocup/i.test(ultimoParrafo)) return 'descubrimiento';

  // PASO 5: Fallbacks
  if (/recuerda.*cita|no olvides|[lts]e esperamos|cualquier.*duda.*aqu[ií]/i.test(tf)) return 'seguimiento';
  if (/\$|precio|costo|consult.*incluye|honorario/i.test(tf)) {
    if (/disponible|espacio|lunes|martes|mi[eé]rcoles|jueves|viernes|s[aá]bado/i.test(tf)) return 'horarios_dados';
    return 'precio_dado';
  }
  if (/ubicaci|direcci|blvd|colonia|consultorio|hospital/i.test(tf) && !/disponib|espacio|horario|cita/i.test(tf)) return 'ubicacion_dada';
  if (/urgencia|emergencia|acudir.*inmediatamente|urolog.*guardia/i.test(tf)) return 'escalamiento';
  if (/bienvenid|encantado|mucho gusto|soy.*dr|asistente.*dr/i.test(tf)) return 'bienvenida';

  return 'conversacion';
}

const faseConversacion = clasificarHibrido();

const esperaRespuesta = /\?/.test(ultimoParrafo) || 
  ['descubrimiento', 'horarios_dados', 'oferta_cita', 'confirmacion'].includes(faseConversacion);

const accionesMap = {
  'confirmacion': 'confirmar_cita',
  'horarios_dados': 'mostrar_horarios',
  'oferta_cita': 'ofrecer_cita',
  'descubrimiento': 'evaluar_sintomas',
  'precio_dado': 'informar_precio',
  'ubicacion_dada': 'informar_ubicacion',
  'escalamiento': 'escalar_urgente',
  'seguimiento': 'recordar_cita',
  'bienvenida': 'presentarse',
  'conversacion': 'continuar'
};
const accionBot = accionesMap[faseConversacion] || 'continuar';

return [{
  json: {
    ...ctx,
    text: limpioData.text || '',
    fase_conversacion: faseConversacion,
    accion_bot: accionBot,
    espera_respuesta: esperaRespuesta,
    conversacion_id: ctx.conversacion_id || null
  }
}];

const ctx = $('9️⃣ Formatear Contexto').first()?.json || $('5️⃣ Procesar Contexto').first()?.json || {};
console.log(`⏸️ Anti-Baneo SKIP: ${ctx.telefono || 'desconocido'} - mensaje no enviado por rate limit`);
return [{ json: { skipped: true, reason: 'anti_baneo', telefono: ctx.telefono || '' } }];
